"""Секция pipeline (таб «Общее» в GUI): индекс result, число потоков для этапов пайплайна."""from __future__ import annotationsfrom types import SimpleNamespacefrom typing import Any# Ключи секции в config.jsonKEY_DISCOVERY_THREADS = "discovery_threads"KEY_EXTRACT_THREADS = "extract_threads"KEY_IMAGE_PROCESSING_THREADS = "image_processing_threads"KEY_MARKDOWN_THREADS = "markdown_threads"KEY_TAGGING_THREADS = "tagging_threads"KEY_CREATE_DOCUMENTS_INDEX = "create_documents_index"DISCOVERY_THREADS_DEFAULT = 1CREATE_DOCUMENTS_INDEX_DEFAULT = TrueDISCOVERY_THREADS_ONLY = 1  # всегда 1EXTRACT_THREADS_MIN, EXTRACT_THREADS_MAX = 1, 16EXTRACT_THREADS_DEFAULT = 4IMAGE_PROCESSING_THREADS_MIN, IMAGE_PROCESSING_THREADS_MAX = 1, 8IMAGE_PROCESSING_THREADS_DEFAULT = 4MARKDOWN_THREADS_MIN, MARKDOWN_THREADS_MAX = 1, 8MARKDOWN_THREADS_DEFAULT = 4TAGGING_THREADS_MIN, TAGGING_THREADS_MAX = 1, 8TAGGING_THREADS_DEFAULT = 4PIPELINE_SETTINGS_UI = SimpleNamespace(    help_sidebar_title="Пояснения",    threads_section_title="Настройка потоков",    create_documents_index_label="Создавать индекс документов",    create_documents_index_hint=(        "При «Да» в папке result создаётся index.md: для каждого файла — заголовок со ссылкой, "        "описание, дата и перечень тегов из метаданных."    ),    extract_threads_label="Извлечение данных",    extract_threads_hint=(        f"Число параллельных задач на этапе извлечения текста и структуры из файлов (PDF, офисные форматы и т.д.). "        f"Допустимо от {EXTRACT_THREADS_MIN} до {EXTRACT_THREADS_MAX}. "        "Больше потоков ускоряет пакет на многоядерном CPU, но повышает нагрузку на диск и память."    ),    image_processing_threads_label="Распознавание изображений",    image_processing_threads_hint=(        f"Параллелизм этапа распознавания изображений (OCR, vision, подготовка к выводу). "        f"Диапазон {IMAGE_PROCESSING_THREADS_MIN}–{IMAGE_PROCESSING_THREADS_MAX}. "        "Имеет смысл подбирать под число ядер и лимиты внешних API."    ),    markdown_threads_label="Создание разметки",    markdown_threads_hint=(        f"Сколько документов одновременно обрабатывается на этапе создания разметки (Markdown), "        f"включая вызовы LLM, если режим это предполагает. Диапазон {MARKDOWN_THREADS_MIN}–{MARKDOWN_THREADS_MAX}."    ),    tagging_threads_label="Тегирование",    tagging_threads_hint=(        f"Число параллельных запросов к LLM в режиме «Пакетная обработка» (раздел «Теггирование»). "        f"При «Линейная обработка» и «Пропустить» не используется. Диапазон {TAGGING_THREADS_MIN}–{TAGGING_THREADS_MAX}."    ),    yandex_ocr_banner_text=(        "При обработке изображений через Яндекс OCR будет только один\n"        "поток обработки — ограничение RPS на стороне сервиса."    ),)PIPELINE_HELP_ARTICLE = """Раздел «Общее»: опция индекса в result и параллелизм этапов пайплайна.Создавать индекс документов — при «Да» в result создаётся index.md: по каждому документу блок с заголовком-ссылкой, описанием, датой и тегами.Этап обхода файлов (discovery) всегда в одном потоке — отдельная настройка не показывается.Извлечение данных — параллельная обработка разных исходных файлов. Распознавание изображений — параллельная обработка картинок на соответствующем этапе. Создание разметки — параллельная обработка документов на этапе выхода в Markdown. Тегирование — максимум одновременных вызовов LLM в режиме «Пакетная обработка» в разделе «Теггирование» (там же выбирается линейная или пакетная обработка).Если выбран Яндекс OCR для изображений, фактически используется один поток на этом этапе из‑за лимитов сервиса.""".strip()class PipelineConfig:    """Секция pipeline в config.json: индекс, параллелизм этапов (таб «Общее» в GUI)."""    PIPELINE_SETTINGS_UI = PIPELINE_SETTINGS_UI    PIPELINE_HELP_ARTICLE = PIPELINE_HELP_ARTICLE    @staticmethod    def create_documents_index_enabled(pipeline: dict[str, Any] | None) -> bool:        """Читает create_documents_index из секции pipeline с умолчанием True."""        from src.modules.project.sections.tagging_config import TaggingConfig        p = pipeline if isinstance(pipeline, dict) else {}        return TaggingConfig.coerce_bool(            p.get(KEY_CREATE_DOCUMENTS_INDEX), CREATE_DOCUMENTS_INDEX_DEFAULT        )    @staticmethod    def get_default() -> dict[str, Any]:        """Возвращает словарь умолчаний для секции pipeline."""        return {            KEY_DISCOVERY_THREADS: DISCOVERY_THREADS_DEFAULT,            KEY_CREATE_DOCUMENTS_INDEX: CREATE_DOCUMENTS_INDEX_DEFAULT,            KEY_EXTRACT_THREADS: EXTRACT_THREADS_DEFAULT,            KEY_IMAGE_PROCESSING_THREADS: IMAGE_PROCESSING_THREADS_DEFAULT,            KEY_MARKDOWN_THREADS: MARKDOWN_THREADS_DEFAULT,            KEY_TAGGING_THREADS: TAGGING_THREADS_DEFAULT,        }    @staticmethod    def validate(data: Any) -> list[str]:        """Проверяет данные секции pipeline. Возвращает список сообщений об ошибках (пустой — данные валидны)."""        errors: list[str] = []        if not isinstance(data, dict):            errors.append("Pipeline: ожидается объект (dict).")            return errors        v = data.get(KEY_CREATE_DOCUMENTS_INDEX)        if v is not None and not isinstance(v, bool):            errors.append(                f"Pipeline: поле {KEY_CREATE_DOCUMENTS_INDEX} должно быть true/false (bool)."            )        v = data.get(KEY_DISCOVERY_THREADS)        if v is not None and (not isinstance(v, int) or v != DISCOVERY_THREADS_ONLY):            errors.append(f"Pipeline: {KEY_DISCOVERY_THREADS} должен быть равен {DISCOVERY_THREADS_ONLY}.")        v = data.get(KEY_EXTRACT_THREADS)        if v is not None and (not isinstance(v, int) or v < EXTRACT_THREADS_MIN or v > EXTRACT_THREADS_MAX):            errors.append(                f"Pipeline: {KEY_EXTRACT_THREADS} должен быть целым числом от {EXTRACT_THREADS_MIN} до {EXTRACT_THREADS_MAX}."            )        v = data.get(KEY_IMAGE_PROCESSING_THREADS)        if v is not None and (            not isinstance(v, int) or v < IMAGE_PROCESSING_THREADS_MIN or v > IMAGE_PROCESSING_THREADS_MAX        ):            errors.append(                f"Pipeline: {KEY_IMAGE_PROCESSING_THREADS} должен быть целым числом от {IMAGE_PROCESSING_THREADS_MIN} до {IMAGE_PROCESSING_THREADS_MAX}."            )        v = data.get(KEY_MARKDOWN_THREADS)        if v is not None and (            not isinstance(v, int) or v < MARKDOWN_THREADS_MIN or v > MARKDOWN_THREADS_MAX        ):            errors.append(                f"Pipeline: {KEY_MARKDOWN_THREADS} должен быть целым числом от {MARKDOWN_THREADS_MIN} до {MARKDOWN_THREADS_MAX}."            )        v = data.get(KEY_TAGGING_THREADS)        if v is not None and (            not isinstance(v, int) or v < TAGGING_THREADS_MIN or v > TAGGING_THREADS_MAX        ):            errors.append(                f"Pipeline: {KEY_TAGGING_THREADS} должен быть целым числом от {TAGGING_THREADS_MIN} до {TAGGING_THREADS_MAX}."            )        return errors